/**
 * Defines the position where to show the chart legend
 * @public
 */
export const legendPositionOptions = ['auto', 'bottom', 'right'] as const;

/**
 * @public
 */
export type LegendPosition = (typeof legendPositionOptions)[number];

/**
 * Defines the position where to show the chart legend
 * @internal
 */
export type ChartLegendOrientation = 'horizontal' | 'vertical';

/**
 * Defines the size of the legend.
 * The ratio is a number included in the interval [0-80].
 * - When legendPosition='right' the ratio is relative to the container width.
 * - When legendPosition='bottom' the ratio is relative to the container height.
 *
 * The option 'auto' enable the automatic initialization depending on the content.
 * of the legend (optimal display).
 * @defaultValue 'auto'.
 * @public
 */
export type LegendRatio = number | 'auto';

/**
 * @public
 */
export interface LegendProps {
  /** The position of the legend relative to the chart. */
  position?: LegendPosition;
  /** Whether the legend should be hidden or not. */
  hidden?: boolean;
  /**
   * Defines the percentage the legend takes against the chart.
   * This applies to the width when the legend is at the right, and to the height when it's places at the bottom.
   * @defaultValue 25%.
   * @deprecated Will be removed, use `initialRatio` instead.
   */
  ratio?: LegendRatio;
  /**
   * Defines the percentage the legend takes against the chart.
   * This applies to the width when the legend is at the right, and to the height when it's places at the bottom, only for the initial rendering.
   * @defaultValue 'auto'.
   */
  initialRatio?: LegendRatio;
  /** Returns the percentage that the legend takes against the chart */
  onRatioChange?: (ratio: number) => void;
}
